import{_ as d,C as a,o as r,c as i,E as s,a3 as l}from"./chunks/framework.BVmBWEBf.js";const n="/versions/v0.10.0/screens/devices/scaler.png",x=JSON.parse('{"title":"Scaler","description":"","frontmatter":{"title":"Scaler","pageClass":"device-doc"},"headers":[],"relativePath":"devices/scaler.md","filePath":"devices/scaler.md"}'),o={name:"devices/scaler.md"};function h(c,t,g,y,p,m){const e=a("DeviceHeading");return r(),i("div",null,[s(e,{slug:"scaler",title:"Scaler"}),t[0]||(t[0]=l('<p>Quantize notes to a scale</p><p><img src="'+n+'" alt="Scaler parameters" class="screen"></p><h2 id="when-to-use-it" tabindex="-1">When to use it <a class="header-anchor" href="#when-to-use-it" aria-label="Permalink to &quot;When to use it&quot;">​</a></h2><p>Use <strong>Scaler</strong> anywhere you need <strong>in-key notes</strong> — after a random source, before Harmony/Arp, or on live input. Choose a preset scale or build a custom one from individual degrees.</p><h2 id="parameters" tabindex="-1">Parameters <a class="header-anchor" href="#parameters" aria-label="Permalink to &quot;Parameters&quot;">​</a></h2><div class="device-params-table"><table tabindex="0"><thead><tr><th>Parameter</th><th>Range</th><th>What it does</th></tr></thead><tbody><tr><td>Bypass</td><td>0 – 1</td><td>When on, the device is disabled and MIDI passes through unchanged.</td></tr><tr><td>Key</td><td>0 – 11</td><td>Root pitch class (C–B) for scale quantization.</td></tr><tr><td>Quantize</td><td>0 – 2</td><td>How out-of-scale notes are corrected (down, up, or filtered out).</td></tr><tr><td>Scale</td><td>0 – 50</td><td>Preset scale from the built-in library, or Custom to use degree toggles.</td></tr><tr><td>I</td><td>0 – 11</td><td>Include scale degree 1 when Scale is Custom (pitch class 0–11).</td></tr><tr><td>I#</td><td>0 – 11</td><td>Include scale degree 2 when Scale is Custom (pitch class 0–11).</td></tr><tr><td>II</td><td>0 – 11</td><td>Include scale degree 3 when Scale is Custom (pitch class 0–11).</td></tr><tr><td>II#</td><td>0 – 11</td><td>Include scale degree 4 when Scale is Custom (pitch class 0–11).</td></tr><tr><td>III</td><td>0 – 11</td><td>Include scale degree 5 when Scale is Custom (pitch class 0–11).</td></tr><tr><td>IV</td><td>0 – 11</td><td>Include scale degree 6 when Scale is Custom (pitch class 0–11).</td></tr><tr><td>IV#</td><td>0 – 11</td><td>Include scale degree 7 when Scale is Custom (pitch class 0–11).</td></tr><tr><td>V</td><td>0 – 11</td><td>Include scale degree 8 when Scale is Custom (pitch class 0–11).</td></tr><tr><td>V#</td><td>0 – 11</td><td>Include scale degree 9 when Scale is Custom (pitch class 0–11).</td></tr><tr><td>VI</td><td>0 – 11</td><td>Include scale degree 10 when Scale is Custom (pitch class 0–11).</td></tr><tr><td>VI#</td><td>0 – 11</td><td>Include scale degree 11 when Scale is Custom (pitch class 0–11).</td></tr><tr><td>VII</td><td>0 – 11</td><td>Include scale degree 12 when Scale is Custom (pitch class 0–11).</td></tr></tbody></table></div><h2 id="parameter-values" tabindex="-1">Parameter values <a class="header-anchor" href="#parameter-values" aria-label="Permalink to &quot;Parameter values&quot;">​</a></h2><h3 id="bypass" tabindex="-1">Bypass <a class="header-anchor" href="#bypass" aria-label="Permalink to &quot;Bypass&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:right;">Value</th><th>Name</th><th>Meaning</th></tr></thead><tbody><tr><td style="text-align:right;">0</td><td>Off</td><td>Device is active and processes MIDI.</td></tr><tr><td style="text-align:right;">1</td><td>On</td><td>Device is bypassed; messages pass through unchanged.</td></tr></tbody></table><h3 id="key" tabindex="-1">Key <a class="header-anchor" href="#key" aria-label="Permalink to &quot;Key&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:right;">Value</th><th>Name</th><th>Meaning</th></tr></thead><tbody><tr><td style="text-align:right;">0</td><td>C</td><td>Root pitch class C.</td></tr><tr><td style="text-align:right;">1</td><td>C#</td><td>Root pitch class C sharp.</td></tr><tr><td style="text-align:right;">2</td><td>D</td><td>Root pitch class D.</td></tr><tr><td style="text-align:right;">3</td><td>D#</td><td>Root pitch class D sharp.</td></tr><tr><td style="text-align:right;">4</td><td>E</td><td>Root pitch class E.</td></tr><tr><td style="text-align:right;">5</td><td>F</td><td>Root pitch class F.</td></tr><tr><td style="text-align:right;">6</td><td>F#</td><td>Root pitch class F sharp.</td></tr><tr><td style="text-align:right;">7</td><td>G</td><td>Root pitch class G.</td></tr><tr><td style="text-align:right;">8</td><td>G#</td><td>Root pitch class G sharp.</td></tr><tr><td style="text-align:right;">9</td><td>A</td><td>Root pitch class A.</td></tr><tr><td style="text-align:right;">10</td><td>A#</td><td>Root pitch class A sharp.</td></tr><tr><td style="text-align:right;">11</td><td>B</td><td>Root pitch class B.</td></tr></tbody></table><h3 id="quantize" tabindex="-1">Quantize <a class="header-anchor" href="#quantize" aria-label="Permalink to &quot;Quantize&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:right;">Value</th><th>Name</th><th>Meaning</th></tr></thead><tbody><tr><td style="text-align:right;">0</td><td>Down</td><td>Snap to the nearest scale degree below the input pitch.</td></tr><tr><td style="text-align:right;">1</td><td>Up</td><td>Snap to the nearest scale degree above the input pitch.</td></tr><tr><td style="text-align:right;">2</td><td>Filter</td><td>Drop notes that are not in the scale.</td></tr></tbody></table><h2 id="available-scales" tabindex="-1">Available scales <a class="header-anchor" href="#available-scales" aria-label="Permalink to &quot;Available scales&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Preset <strong>Scale</strong> values 1–50 in the Scaler device. Set <strong>Scale</strong> to <strong>Custom</strong> (0) to build your own pool from the <strong>Degree</strong> toggles instead.</p></div><table tabindex="0"><thead><tr><th style="text-align:right;">#</th><th>Scale</th><th>Description</th></tr></thead><tbody><tr><td style="text-align:right;">1</td><td>Chromatic</td><td>All twelve semitones — no quantization.</td></tr><tr><td style="text-align:right;">2</td><td>Major</td><td>Ionian major — the common major scale.</td></tr><tr><td style="text-align:right;">3</td><td>Natural Minor</td><td>Natural minor (Aeolian).</td></tr><tr><td style="text-align:right;">4</td><td>Pentatonic Major</td><td>Major pentatonic — five notes, no semitone clashes.</td></tr><tr><td style="text-align:right;">5</td><td>Pentatonic Minor</td><td>Minor pentatonic — blues-friendly five-note set.</td></tr><tr><td style="text-align:right;">6</td><td>Blues</td><td>Blues hexatonic with lowered fifth.</td></tr><tr><td style="text-align:right;">7</td><td>Harmonic Minor</td><td>Minor with raised seventh (leading tone).</td></tr><tr><td style="text-align:right;">8</td><td>Melodic Minor</td><td>Ascending melodic minor.</td></tr><tr><td style="text-align:right;">9</td><td>Dorian</td><td>Dorian mode — minor with raised sixth.</td></tr><tr><td style="text-align:right;">10</td><td>Mixolydian</td><td>Mixolydian — major with lowered seventh.</td></tr><tr><td style="text-align:right;">11</td><td>Lydian</td><td>Lydian — major with raised fourth.</td></tr><tr><td style="text-align:right;">12</td><td>Phrygian</td><td>Phrygian — minor with lowered second.</td></tr><tr><td style="text-align:right;">13</td><td>Locrian</td><td>Locrian — diminished fifth flavor.</td></tr><tr><td style="text-align:right;">14</td><td>Whole Tone</td><td>Whole-tone — six equal whole steps.</td></tr><tr><td style="text-align:right;">15</td><td>Bebop Dominant</td><td>Bebop dominant — passing tone on dominant 7th.</td></tr><tr><td style="text-align:right;">16</td><td>Bebop Major</td><td>Bebop major — passing tone in major.</td></tr><tr><td style="text-align:right;">17</td><td>Bebop Minor</td><td>Bebop minor — passing tone in minor.</td></tr><tr><td style="text-align:right;">18</td><td>Harmonic Major</td><td>Major with harmonic minor raised seventh.</td></tr><tr><td style="text-align:right;">19</td><td>Altered</td><td>Super Locrian / altered dominant.</td></tr><tr><td style="text-align:right;">20</td><td>Half-Whole Diminished</td><td>Half–whole diminished.</td></tr><tr><td style="text-align:right;">21</td><td>Whole-Half Diminished</td><td>Whole–half diminished.</td></tr><tr><td style="text-align:right;">22</td><td>Lydian Dominant</td><td>Lydian dominant — Mixolydian with #4.</td></tr><tr><td style="text-align:right;">23</td><td>Diminished Whole Tone</td><td>Diminished whole-tone hybrid.</td></tr><tr><td style="text-align:right;">24</td><td>Overtone</td><td>Overtone / acoustic scale.</td></tr><tr><td style="text-align:right;">25</td><td>Augmented</td><td>Augmented — major thirds cycle.</td></tr><tr><td style="text-align:right;">26</td><td>Japanese</td><td>Japanese insen-style pentatonic.</td></tr><tr><td style="text-align:right;">27</td><td>Egyptian</td><td>Egyptian pentatonic.</td></tr><tr><td style="text-align:right;">28</td><td>Flamenco</td><td>Flamenco / Spanish gypsy.</td></tr><tr><td style="text-align:right;">29</td><td>2x Harmonic Major</td><td>Double harmonic major.</td></tr><tr><td style="text-align:right;">30</td><td>Hungarian Minor</td><td>Hungarian minor.</td></tr><tr><td style="text-align:right;">31</td><td>Persian</td><td>Persian — augmented second flavor.</td></tr><tr><td style="text-align:right;">32</td><td>Neapolitan Minor</td><td>Neapolitan minor.</td></tr><tr><td style="text-align:right;">33</td><td>Neapolitan Major</td><td>Neapolitan major.</td></tr><tr><td style="text-align:right;">34</td><td>Raga Bhairav</td><td>Raga Bhairav.</td></tr><tr><td style="text-align:right;">35</td><td>Indian</td><td>Indian pentatonic variant.</td></tr><tr><td style="text-align:right;">36</td><td>Chinese</td><td>Chinese pentatonic.</td></tr><tr><td style="text-align:right;">37</td><td>Arabian</td><td>Arabian — hijaz-like.</td></tr><tr><td style="text-align:right;">38</td><td>Balinese</td><td>Balinese pelog-derived.</td></tr><tr><td style="text-align:right;">39</td><td>Balinese Pelog</td><td>Balinese pelog (alternate).</td></tr><tr><td style="text-align:right;">40</td><td>Enigmatic</td><td>Enigmatic — unusual intervals.</td></tr><tr><td style="text-align:right;">41</td><td>Prometheus</td><td>Prometheus — mystic chord color.</td></tr><tr><td style="text-align:right;">42</td><td>Messiaen&#39;s Mode 2</td><td>Messiaen mode 2 (octatonic).</td></tr><tr><td style="text-align:right;">43</td><td>Messiaen&#39;s Mode 3</td><td>Messiaen mode 3.</td></tr><tr><td style="text-align:right;">44</td><td>Pentatonic Neutral</td><td>Neutral pentatonic.</td></tr><tr><td style="text-align:right;">45</td><td>Nine-Note Jazz</td><td>Nine-note jazz scale.</td></tr><tr><td style="text-align:right;">46</td><td>Hexatonic Blues</td><td>Hexatonic blues variant.</td></tr><tr><td style="text-align:right;">47</td><td>Freygish</td><td>Phrygian dominant (Freygish).</td></tr><tr><td style="text-align:right;">48</td><td>Byzantine</td><td>Byzantine double harmonic.</td></tr><tr><td style="text-align:right;">49</td><td>Tarantella</td><td>Tarantella — southern Italian flavor.</td></tr><tr><td style="text-align:right;">50</td><td>Raga Kafi</td><td>Raga Kafi.</td></tr></tbody></table>',16))])}const b=d(o,[["render",h]]);export{x as __pageData,b as default};
